16	// config item base class
17	class ConfigItem {
18	 public:
19	  enum ValueType { kNull, kScalar, kList, kMap };
20	
21	  ConfigItem() = default;  // null
22	  virtual ~ConfigItem() = default;
23	
24	  ValueType type() const { return type_; }
25	
26	  virtual bool empty() const { return type_ == kNull; }
27	
28	 protected:
29	  ConfigItem(ValueType type) : type_(type) {}
30	
31	  ValueType type_ = kNull;
32	};
33	
34	class ConfigValue : public ConfigItem {
35	 public:
36	  ConfigValue() : ConfigItem(kScalar) {}
37	  RIME_DLL ConfigValue(bool value);
38	  RIME_DLL ConfigValue(int value);
39	  RIME_DLL ConfigValue(double value);
40	  RIME_DLL ConfigValue(const char* value);
41	  RIME_DLL ConfigValue(const string& value);
42	
43	  // schalar value accessors
44	  bool GetBool(bool* value) const;
45	  RIME_DLL bool GetInt(int* value) const;
46	  bool GetDouble(double* value) const;
47	  RIME_DLL bool GetString(string* value) const;
48	  bool SetBool(bool value);
49	  bool SetInt(int value);
50	  bool SetDouble(double value);
51	  bool SetString(const char* value);
52	  bool SetString(const string& value);
53	
54	  const string& str() const { return value_; }
55	
56	  bool empty() const override { return value_.empty(); }
57	
58	 protected:
59	  string value_;
60	};
61	
62	class ConfigList : public ConfigItem {
63	 public:
64	  using Sequence = vector<of<ConfigItem>>;
65	  using Iterator = Sequence::iterator;
66	
67	  ConfigList() : ConfigItem(kList) {}
68	  RIME_DLL an<ConfigItem> GetAt(size_t i) const;
69	  RIME_DLL an<ConfigValue> GetValueAt(size_t i) const;
70	  RIME_DLL bool SetAt(size_t i, an<ConfigItem> element);
71	  bool Insert(size_t i, an<ConfigItem> element);
72	  RIME_DLL bool Append(an<ConfigItem> element);
73	  bool Resize(size_t size);
74	  RIME_DLL bool Clear();
75	  RIME_DLL size_t size() const;
76	
77	  Iterator begin();
78	  Iterator end();
79	
80	  bool empty() const override { return seq_.empty(); }
81	
82	 protected:
83	  Sequence seq_;
84	};
85	
86	// limitation: map keys have to be strings, preferably alphanumeric
87	class ConfigMap : public ConfigItem {
88	 public:
89	  using Map = map<string, an<ConfigItem>>;
90	  using Iterator = Map::iterator;
91	
92	  ConfigMap() : ConfigItem(kMap) {}
93	  RIME_DLL bool HasKey(const string& key) const;
94	  RIME_DLL an<ConfigItem> Get(const string& key) const;
95	  RIME_DLL an<ConfigValue> GetValue(const string& key) const;
96	  RIME_DLL bool Set(const string& key, an<ConfigItem> element);
97	  bool Clear();
98	
99	  Iterator begin();
100	  Iterator end();
101	
102	  bool empty() const override { return map_.empty(); }
103	
104	 protected:
105	  Map map_;
106	};
107	
108	namespace {
109	
110	template <class T>
111	an<ConfigItem> AsConfigItem(const T& x, const std::false_type&) {
112	  return New<ConfigValue>(x);
113	};
114	
115	template <class T>
116	an<ConfigItem> AsConfigItem(const T& x, const std::true_type&) {
117	  return x;
118	};
119	
120	}  // namespace
121	
122	class ConfigData;
123	class ConfigListEntryRef;
124	class ConfigMapEntryRef;
125	
126	class ConfigItemRef {
127	 public:
128	  ConfigItemRef(ConfigData* data) : data_(data) {}
129	  virtual ~ConfigItemRef() = default;
130	  operator an<ConfigItem>() const { return GetItem(); }
131	  an<ConfigItem> operator*() const { return GetItem(); }
132	  template <class T>
133	  ConfigItemRef& operator=(const T& x) {
134	    SetItem(AsConfigItem(x, std::is_convertible<T, an<ConfigItem>>()));
135	    return *this;
136	  }
137	  ConfigListEntryRef operator[](size_t index);
138	  ConfigMapEntryRef operator[](const string& key);
139	
140	  RIME_DLL bool IsNull() const;
141	  bool IsValue() const;
142	  RIME_DLL bool IsList() const;
143	  bool IsMap() const;
144	
145	  RIME_DLL bool ToBool() const;
146	  RIME_DLL int ToInt() const;
147	  double ToDouble() const;
148	  RIME_DLL string ToString() const;
149	
150	  RIME_DLL an<ConfigList> AsList();
151	  RIME_DLL an<ConfigMap> AsMap();
152	  RIME_DLL void Clear();
153	
154	  // list
155	  RIME_DLL bool Append(an<ConfigItem> item);
156	  RIME_DLL size_t size() const;
157	  // map
158	  RIME_DLL bool HasKey(const string& key) const;
159	
160	  RIME_DLL bool modified() const;
161	  RIME_DLL void set_modified();
162	
163	 protected:
164	  virtual an<ConfigItem> GetItem() const = 0;
165	  virtual void SetItem(an<ConfigItem> item) = 0;
166	
167	  ConfigData* data_;
168	};
169	
170	class ConfigListEntryRef : public ConfigItemRef {
171	 public:
172	  ConfigListEntryRef(ConfigData* data, an<ConfigList> list, size_t index)
173	      : ConfigItemRef(data), list_(list), index_(index) {}
174	  using ConfigItemRef::operator=;
175	
176	 protected:
177	  an<ConfigItem> GetItem() const { return list_->GetAt(index_); }
178	  void SetItem(an<ConfigItem> item) {
179	    list_->SetAt(index_, item);
180	    set_modified();
181	  }
182	
183	 private:
184	  an<ConfigList> list_;
185	  size_t index_;
186	};
187	
188	class ConfigMapEntryRef : public ConfigItemRef {
189	 public:
190	  ConfigMapEntryRef(ConfigData* data, an<ConfigMap> map, const string& key)
191	      : ConfigItemRef(data), map_(map), key_(key) {}
192	  using ConfigItemRef::operator=;
193	
194	 protected:
195	  an<ConfigItem> GetItem() const { return map_->Get(key_); }
196	  void SetItem(an<ConfigItem> item) {
197	    map_->Set(key_, item);
198	    set_modified();
199	  }
200	
201	 private:
202	  an<ConfigMap> map_;
203	  string key_;
204	};
205	
206	inline ConfigListEntryRef ConfigItemRef::operator[](size_t index) {
207	  return ConfigListEntryRef(data_, AsList(), index);
208	}
209	
210	inline ConfigMapEntryRef ConfigItemRef::operator[](const string& key) {
211	  return ConfigMapEntryRef(data_, AsMap(), key);
212	}
213	
214	}  // namespace rime
215	
216	#endif  // RIME_CONFIG_TYPES_H_
