34	bool ConfigValue::GetBool(bool* value) const {
35	  if (!value || value_.empty())
36	    return false;
37	  string bstr = value_;
38	  boost::to_lower(bstr);
39	  if ("true" == bstr) {
40	    *value = true;
41	    return true;
42	  } else if ("false" == bstr) {
43	    *value = false;
44	    return true;
45	  } else
46	    return false;
47	}
48	
49	bool ConfigValue::GetInt(int* value) const {
50	  if (!value || value_.empty())
51	    return false;
52	  // try to parse hex number
53	  if (boost::starts_with(value_, "0x")) {
54	    char* p = NULL;
55	    unsigned int hex = std::strtoul(value_.c_str(), &p, 16);
56	    if (*p == '\0') {
57	      *value = static_cast<int>(hex);
58	      return true;
59	    }
60	  }
61	  // decimal
62	  try {
63	    *value = std::stoi(value_);
64	  } catch (...) {
65	    return false;
66	  }
67	  return true;
68	}
69	
70	bool ConfigValue::GetDouble(double* value) const {
71	  if (!value || value_.empty())
72	    return false;
73	  try {
74	    *value = std::stod(value_);
75	  } catch (...) {
76	    return false;
77	  }
78	  return true;
79	}
80	
81	bool ConfigValue::GetString(string* value) const {
82	  if (!value)
83	    return false;
84	  *value = value_;
85	  return true;
86	}
87	
88	bool ConfigValue::SetBool(bool value) {
89	  value_ = value ? "true" : "false";
90	  return true;
91	}
92	
93	bool ConfigValue::SetInt(int value) {
94	  value_ = std::to_string(value);
95	  return true;
96	}
97	
98	bool ConfigValue::SetDouble(double value) {
99	  value_ = std::to_string(value);
100	  return true;
101	}
102	
103	bool ConfigValue::SetString(const char* value) {
104	  value_ = value;
105	  return true;
106	}
107	
108	bool ConfigValue::SetString(const string& value) {
109	  value_ = value;
110	  return true;
111	}
