113	// ConfigList members
114	
115	an<ConfigItem> ConfigList::GetAt(size_t i) const {
116	  if (i >= seq_.size())
117	    return nullptr;
118	  else
119	    return seq_[i];
120	}
121	
122	an<ConfigValue> ConfigList::GetValueAt(size_t i) const {
123	  return As<ConfigValue>(GetAt(i));
124	}
125	
126	bool ConfigList::SetAt(size_t i, an<ConfigItem> element) {
127	  if (i >= seq_.size())
128	    seq_.resize(i + 1);
129	  seq_[i] = element;
130	  return true;
131	}
132	
133	bool ConfigList::Insert(size_t i, an<ConfigItem> element) {
134	  if (i > seq_.size()) {
135	    seq_.resize(i);
136	  }
137	  seq_.insert(seq_.begin() + i, element);
138	  return true;
139	}
140	
141	bool ConfigList::Append(an<ConfigItem> element) {
142	  seq_.push_back(element);
143	  return true;
144	}
145	
146	bool ConfigList::Resize(size_t size) {
147	  seq_.resize(size);
148	  return true;
149	}
150	
151	bool ConfigList::Clear() {
152	  seq_.clear();
153	  return true;
154	}
155	
156	size_t ConfigList::size() const {
157	  return seq_.size();
158	}
159	
160	ConfigList::Iterator ConfigList::begin() {
161	  return seq_.begin();
162	}
163	
164	ConfigList::Iterator ConfigList::end() {
165	  return seq_.end();
166	}
