207	  auto item = GetItem();
208	  return !item || item->type() == ConfigItem::kNull;
209	}
210	
211	bool ConfigItemRef::IsValue() const {
212	  auto item = GetItem();
213	  return item && item->type() == ConfigItem::kScalar;
214	}
