217	  auto item = GetItem();
218	  return item && item->type() == ConfigItem::kList;
219	}
220	
221	bool ConfigItemRef::IsMap() const {
222	  auto item = GetItem();
223	  return item && item->type() == ConfigItem::kMap;
224	}
