226	bool ConfigItemRef::ToBool() const {
227	  bool value = false;
228	  if (auto item = As<ConfigValue>(GetItem())) {
229	    item->GetBool(&value);
230	  }
231	  return value;
232	}
233	
234	int ConfigItemRef::ToInt() const {
235	  int value = 0;
236	  if (auto item = As<ConfigValue>(GetItem())) {
237	    item->GetInt(&value);
238	  }
239	  return value;
240	}
241	
242	double ConfigItemRef::ToDouble() const {
243	  double value = 0.0;
244	  if (auto item = As<ConfigValue>(GetItem())) {
245	    item->GetDouble(&value);
