258	an<ConfigList> ConfigItemRef::AsList() {
259	  auto list = As<ConfigList>(GetItem());
260	  if (!list)
261	    SetItem(list = New<ConfigList>());
262	  return list;
263	}
264	
265	an<ConfigMap> ConfigItemRef::AsMap() {
266	  auto map = As<ConfigMap>(GetItem());
267	  if (!map)
268	    SetItem(map = New<ConfigMap>());
269	  return map;
270	}
271	
272	void ConfigItemRef::Clear() {
273	  SetItem(nullptr);
274	}
275	
276	bool ConfigItemRef::Append(an<ConfigItem> item) {
277	  if (AsList()->Append(item)) {
278	    set_modified();
279	    return true;
280	  }
281	  return false;
282	}
283	
284	size_t ConfigItemRef::size() const {
285	  auto list = As<ConfigList>(GetItem());
286	  return list ? list->size() : 0;
287	}
288	
289	bool ConfigItemRef::HasKey(const string& key) const {
290	  auto map = As<ConfigMap>(GetItem());
291	  return map ? map->HasKey(key) : false;
292	}
