23	  // CAVEAT: Config instances created without argument will NOT
24	  // be managed by ConfigComponent
25	  RIME_DLL Config();
26	  RIME_DLL virtual ~Config();
27	  // instances of Config with identical config id share a copy of config data
28	  // in the ConfigComponent
29	  explicit Config(an<ConfigData> data);
30	
31	  // returns whether actually saved to file.
32	  bool Save();
33	  bool LoadFromStream(std::istream& stream);
34	  bool SaveToStream(std::ostream& stream);
35	  RIME_DLL bool LoadFromFile(const path& file_path);
36	  RIME_DLL bool SaveToFile(const path& file_path);
37	
38	  // access a tree node of a particular type with "path/to/node"
39	  RIME_DLL bool IsNull(const string& path);
40	  bool IsValue(const string& path);
41	  RIME_DLL bool IsList(const string& path);
42	  RIME_DLL bool IsMap(const string& path);
43	  RIME_DLL bool GetBool(const string& path, bool* value);
44	  RIME_DLL bool GetInt(const string& path, int* value);
45	  RIME_DLL bool GetDouble(const string& path, double* value);
46	  RIME_DLL bool GetString(const string& path, string* value);
47	  RIME_DLL size_t GetListSize(const string& path);
48	
49	  an<ConfigItem> GetItem(const string& path);
50	  an<ConfigValue> GetValue(const string& path);
51	  RIME_DLL an<ConfigList> GetList(const string& path);
52	  RIME_DLL an<ConfigMap> GetMap(const string& path);
53	
54	  // setters
55	  bool SetBool(const string& path, bool value);
56	  RIME_DLL bool SetInt(const string& path, int value);
57	  bool SetDouble(const string& path, double value);
58	  RIME_DLL bool SetString(const string& path, const char* value);
59	  bool SetString(const string& path, const string& value);
60	  // setter for adding or replacing items in the tree
61	  RIME_DLL bool SetItem(const string& path, an<ConfigItem> item);
62	  using ConfigItemRef::operator=;
63	
64	 protected:
65	  an<ConfigItem> GetItem() const;
66	  void SetItem(an<ConfigItem> item);
67	
68	  an<ConfigData> data_;
69	};
