109	class ConfigComponent : public ConfigComponentBase {
110	 public:
111	  ConfigComponent(const ResourceType& resource_type =
112	                      ResourceProvider::kDefaultResourceType)
113	      : ConfigComponentBase(
114	            ResourceProvider::CreateResourceResolver(resource_type)) {}
115	  ConfigComponent(function<void(Loader* loader)> setup)
116	      : ConfigComponentBase(ResourceProvider::CreateResourceResolver(
117	            ResourceProvider::kDefaultResourceType)) {
118	    setup(&loader_);
