33	bool ConfigData::LoadFromStream(std::istream& stream) {
34	  if (!stream.good()) {
35	    LOG(ERROR) << "failed to load config from stream.";
36	    return false;
37	  }
38	  try {
39	    YAML::Node doc = YAML::Load(stream);
40	    root = ConvertFromYaml(doc, nullptr);
41	  } catch (YAML::Exception& e) {
42	    LOG(ERROR) << "Error parsing YAML: " << e.what();
43	    return false;
44	  }
45	  return true;
46	}
