63	bool ConfigData::LoadFromFile(const path& file_path, ConfigCompiler* compiler) {
64	  // update status
65	  file_path_ = file_path;
66	  modified_ = false;
67	  root.reset();
68	  if (!std::filesystem::exists(file_path)) {
69	    if (!boost::ends_with(file_path.u8string(), ".custom.yaml"))
70	      LOG(WARNING) << "nonexistent config file '" << file_path << "'.";
71	    return false;
72	  }
73	  LOG(INFO) << "loading config file '" << file_path << "'.";
74	  try {
75	    YAML::Node doc = YAML::LoadFile(file_path.string());
76	    root = ConvertFromYaml(doc, compiler);
77	  } catch (YAML::Exception& e) {
78	    LOG(ERROR) << "Error parsing YAML \"" << file_path << "\" : " << e.what();
79	    return false;
80	  }
81	  return true;
82	}
