266	  DLOG(INFO) << "PatchLiteral::Resolve()";
267	  bool success = true;
268	  for (const auto& entry : *patch) {
269	    const auto& key = entry.first;
270	    const auto& value = entry.second;
271	    LOG(INFO) << "patching " << key;
272	    if (!EditNode(target, key, value, false)) {
273	      LOG(ERROR) << "error applying patch to " << key;
274	      success = false;
275	    }
276	  }
277	  return success;
