336	Reference ConfigCompiler::CreateReference(const string& qualified_path) {
337	  auto end = qualified_path.find_last_of("?");
338	  bool optional = end != string::npos;
339	  auto separator = qualified_path.find_first_of(":");
340	  string resource_id = resource_resolver_->ToResourceId(
341	      (separator == string::npos || separator == 0)
342	          ? graph_->current_resource_id()
343	          : qualified_path.substr(0, separator));
344	  string local_path =
345	      (separator == string::npos)
346	          ? qualified_path.substr(0, end)
347	          : qualified_path.substr(separator + 1,
348	                                  optional ? end - separator - 1 : end);
349	  return Reference{resource_id, local_path, optional};
350	}
