385	an<ConfigResource> ConfigCompiler::Compile(const string& file_name) {
386	  auto resource_id = resource_resolver_->ToResourceId(file_name);
387	  auto resource = New<ConfigResource>(resource_id, New<ConfigData>());
388	  graph_->resources[resource_id] = resource;
389	  Push(resource);
390	  resource->loaded = resource->data->LoadFromFile(
391	      resource_resolver_->ResolvePath(resource_id), this);
392	  Pop();
393	  if (plugin_)
394	    plugin_->ReviewCompileOutput(this, resource);
395	  return resource;
396	}
