493	// Includes contents of nodes at specified paths.
494	// __include: path/to/local/node
495	// __include: filename[.yaml]:/path/to/external/node
496	static bool ParseInclude(ConfigCompiler* compiler, const an<ConfigItem>& item) {
497	  if (Is<ConfigValue>(item)) {
498	    auto path = As<ConfigValue>(item)->str();
499	    DLOG(INFO) << "ParseInclude(" << path << ")";
500	    compiler->AddDependency(
501	        New<IncludeReference>(compiler->CreateReference(path)));
502	    return true;
503	  }
504	  return false;
505	}
