545	bool ConfigCompiler::Parse(const string& key, const an<ConfigItem>& item) {
546	  DLOG(INFO) << "ConfigCompiler::Parse(" << key << ")";
547	  if (key == INCLUDE_DIRECTIVE) {
548	    return ParseInclude(this, item);
549	  }
550	  if (key == PATCH_DIRECTIVE) {
551	    return ParseList(ParsePatch, this, item);
552	  }
553	  return false;
554	}
