557	  DLOG(INFO) << "Link(" << target->resource_id << ")";
558	  auto found = graph_->resources.find(target->resource_id);
559	  if (found == graph_->resources.end()) {
560	    LOG(ERROR) << "resource not found: " << target->resource_id;
