15	enum DependencyPriority {
16	  kPendingChild = 0,
17	  kInclude = 1,
18	  kPatch = 2,
19	};
20	
21	struct Dependency {
22	  an<ConfigItemRef> target;
23	
24	  virtual DependencyPriority priority() const = 0;
25	  bool blocking() const { return priority() > kPendingChild; }
26	  virtual string repr() const = 0;
27	  Dependency& TargetedAt(an<ConfigItemRef> target) {
28	    this->target = target;
29	    return *this;
30	  }
31	  virtual bool Resolve(ConfigCompiler* compiler) = 0;
32	};
33	
34	std::ostream& operator<<(std::ostream& stream, const Dependency& dependency);
35	
36	struct PendingChild : Dependency {
37	  string child_path;
38	  an<ConfigItemRef> child_ref;
39	
40	  PendingChild(const string& path, const an<ConfigItemRef>& ref)
41	      : child_path(path), child_ref(ref) {}
42	  DependencyPriority priority() const override { return kPendingChild; }
43	  string repr() const override { return "PendingChild(" + child_path + ")"; }
44	  bool Resolve(ConfigCompiler* compiler) override;
45	};
46	
47	struct IncludeReference : Dependency {
48	  Reference reference;
49	
50	  IncludeReference(const Reference& r) : reference(r) {}
51	  DependencyPriority priority() const override { return kInclude; }
52	  string repr() const override { return "Include(" + reference.repr() + ")"; }
53	  bool Resolve(ConfigCompiler* compiler) override;
54	};
55	
56	struct PatchReference : Dependency {
57	  Reference reference;
58	
59	  PatchReference(const Reference& r) : reference(r) {}
60	  DependencyPriority priority() const override { return kPatch; }
61	  string repr() const override { return "Patch(" + reference.repr() + ")"; }
62	  bool Resolve(ConfigCompiler* compiler) override;
63	};
64	
65	struct PatchLiteral : Dependency {
66	  an<ConfigMap> patch;
67	
68	  PatchLiteral(an<ConfigMap> map) : patch(map) {}
69	  DependencyPriority priority() const override { return kPatch; }
70	  string repr() const override { return "Patch(<literal>)"; }
71	  bool Resolve(ConfigCompiler* compiler) override;
72	};
