19	  if (!boost::ends_with(resource->resource_id, ".schema"))
20	    return true;
21	  {
22	    auto target = Cow(resource, "menu");
23	    Reference reference{"default", "menu", true};
24	    if (!IncludeReference{reference}.TargetedAt(target).Resolve(compiler)) {
25	      LOG(ERROR) << "failed to include section " << reference;
26	      return false;
27	    }
28	  }
