10	
11	static string remove_suffix(const string& input, const string& suffix) {
12	  return boost::ends_with(input, suffix)
13	             ? input.substr(0, input.length() - suffix.length())
14	             : input;
15	}
16	
17	// auto-patch applies to all loaded config resources, including dependencies.
18	// therefore it's done at the end of Compile phase.
19	bool AutoPatchConfigPlugin::ReviewCompileOutput(ConfigCompiler* compiler,
20	                                                an<ConfigResource> resource) {
21	  if (boost::ends_with(resource->resource_id, ".custom"))
22	    return true;
23	  // skip auto-patch if there is already an explicit `__patch` at the root node
24	  auto root_deps = compiler->GetDependencies(resource->resource_id + ":");
25	  if (!root_deps.empty() && root_deps.back()->priority() >= kPatch)
26	    return true;
27	  auto patch_resource_id =
28	      remove_suffix(resource->resource_id, ".schema") + ".custom";
29	  LOG(INFO) << "auto-patch " << resource->resource_id
30	            << ":/__patch: " << patch_resource_id << ":/patch?";
31	  compiler->Push(resource);
32	  compiler->AddDependency(
33	      New<PatchReference>(Reference{patch_resource_id, "patch", true}));
34	  compiler->Pop();
35	  return true;
36	}
37	
38	bool AutoPatchConfigPlugin::ReviewLinkOutput(ConfigCompiler* compiler,
39	                                             an<ConfigResource> resource) {
40	  return true;
41	}
